import{_ as i,o as t,c as a,a3 as s}from"./chunks/framework.LBeL10WQ.js";const g=JSON.parse('{"title":"Process & Validation","description":"","frontmatter":{"title":"Process & Validation"},"headers":[],"relativePath":"en/advertisers/display-email/workflow.md","filePath":"en/advertisers/display-email/workflow.md"}'),o={name:"en/advertisers/display-email/workflow.md"};function n(r,e,d,l,c,p){return t(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="campaign-workflow" tabindex="-1">Campaign Workflow <a class="header-anchor" href="#campaign-workflow" aria-label="Permalink to &quot;Campaign Workflow&quot;">​</a></h1><p>Deploying a newsletter insert is fast. Here are the steps from submission to broadcast.</p><hr><div class="gi-step"><div class="gi-step-num">1</div><div class="gi-step-body"><h3>Sending creative elements</h3><p>Transmit to the distributor (via the getinside platform):</p><ul><li><strong>The visual</strong> — a JPG, PNG, or GIF image respecting the <a href="./specs">technical specifications</a>.</li><li><strong>The destination link</strong> — the URL of the landing page where clicks should be redirected.</li></ul></div></div><div class="gi-step"><div class="gi-step-num">2</div><div class="gi-step-body"><h3>Tracking Configuration</h3><p>The getinside team generates a **unique tracked redirection link** (`gtinsi.de` format) and sends it to the distributor. This link counts every click on your banner.</p><p>To measure sales in Google Analytics, add UTM parameters to your final URL:<br><code>mysite.com?utm_source=getinside&amp;utm_medium=display-email&amp;utm_campaign=spring</code></p></div></div><div class="gi-step"><div class="gi-step-num">3</div><div class="gi-step-body"><h3>Integration and Validation (Proof)</h3><p>The distributor integrates your image into their newsletter and sends you a Proof (BAT) for preview.</p><p>Check the rendering — especially on mobile — then validate on the platform.</p></div></div><div class="warning custom-block"><p class="custom-block-title">Required action to unblock sending</p><ol><li>Log in to <a href="https://app.getinside.media/" target="_blank">app.getinside.media</a>.</li><li>Open the relevant campaign.</li><li>Click the <strong>&quot;Validate campaign&quot;</strong> button.</li></ol><p>Until you validate, the newsletter will not be sent.</p></div><div class="gi-step"><div class="gi-step-num done">4</div><div class="gi-step-body"><h3>Broadcast</h3><p>Once both validations are recorded (advertiser + distributor), the newsletter is sent on the scheduled date. Track clicks in real-time from your dashboard.</p></div></div>',8)])])}const h=i(o,[["render",n]]);export{g as __pageData,h as default};
